def max_coins(nums: list[int]) -> int:
    n = len(nums)
    A = [1] + nums + [1]
    dp = [[0] * (n + 2) for _ in range(n + 2)]
    for length in range(1, n + 1):
        for i in range(1, n - length + 2):
            j = i + length - 1
            for k in range(i, j + 1):
                dp[i][j] = max(dp[i][j], dp[i][k-1] + dp[k+1][j] + A[i-1] * A[k] * A[j+1])
    return dp[1][n]

def matrix_mult(A, B, mod=None):
    res = [
        [A[0][0]*B[0][0] + A[0][1]*B[1][0], A[0][0]*B[0][1] + A[0][1]*B[1][1]],
        [A[1][0]*B[0][0] + A[1][1]*B[1][0], A[1][0]*B[0][1] + A[1][1]*B[1][1]]
    ]
    if mod is not None:
        res = [[x % mod for x in row] for row in res]
    return res

def matrix_power(M, n, mod=None):
    if n == 0:
        return [[1, 0], [0, 1]]
    result = [[1, 0], [0, 1]]
    base = M if mod is None else [[x % mod for x in row] for row in M]
    while n > 0:
        if n % 2 == 1:
            result = matrix_mult(result, base, mod)
        base = matrix_mult(base, base, mod)
        n //= 2
    return result

def fibonacci(n):
    if n == 0:
        return 0
    M = [[1, 1], [1, 0]]
    Mn = matrix_power(M, n)
    return Mn[0][1]

def pisano_period(m):
    if m == 1:
        return 1
    M = [[1, 1], [1, 0]]
    current = [[1, 0], [0, 1]]
    for k in range(1, m * m + 1):
        current = matrix_mult(current, M, mod=m)
        if current == [[1, 0], [0, 1]]:
            return k
    return None

class TreeNode:
    def __init__(self, val="", left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def serialize(root) -> str:
    if not root:
        return "-1:"
    res = []
    stack = [root]
    while stack:
        node = stack.pop()
        if node is None:
            res.append("-1:")
        else:
            res.append(f"{len(node.val)}:{node.val}")
            stack.append(node.right)
            stack.append(node.left)
    return "".join(res)

def deserialize(data) -> 'TreeNode | None':
    if not data:
        return None

    idx = 0

    def parse_next():
        nonlocal idx
        colon = data.find(':', idx)
        if colon == -1:
            return None, idx
        length_str = data[idx:colon]
        idx = colon + 1
        length = int(length_str)
        if length == -1:
            return None, idx
        val = data[idx:idx+length]
        idx += length
        return TreeNode(val), idx

    root, _ = parse_next()
    if root is None:
        return None

    stack = [root]
    while stack:
        node = stack.pop()
        if node is not None:
            left, _ = parse_next()
            right, _ = parse_next()
            node.left = left
            node.right = right
            stack.append(right)
            stack.append(left)

    return root

class DirectedGraph:
    def __init__(self, n: int):
        self.n = n
        self.adj = [[] for _ in range(n)]
        self.indegree = [0] * n

    def add_edge(self, u: int, v: int) -> None:
        self.adj[u].append(v)
        self.indegree[v] += 1

    def has_cycle(self) -> bool:
        indeg = list(self.indegree)
        queue = [i for i in range(self.n) if indeg[i] == 0]
        count = 0
        while queue:
            u = queue.pop(0)
            count += 1
            for v in self.adj[u]:
                indeg[v] -= 1
                if indeg[v] == 0:
                    queue.append(v)
        return count < self.n

    def topological_sort(self) -> list[int] | None:
        indeg = list(self.indegree)
        queue = [i for i in range(self.n) if indeg[i] == 0]
        order = []
        while queue:
            u = queue.pop(0)
            order.append(u)
            for v in self.adj[u]:
                indeg[v] -= 1
                if indeg[v] == 0:
                    queue.append(v)
        return order if len(order) == self.n else None

    def all_topological_sorts(self) -> list[list[int]]:
        if self.has_cycle():
            return []

        indeg = list(self.indegree)
        available = sorted([i for i in range(self.n) if indeg[i] == 0])
        result = []

        def dfs(path, current_indeg, current_available):
            if len(path) == self.n:
                result.append(list(path))
                return

            for i, node in enumerate(current_available):
                path.append(node)
                next_indeg = list(current_indeg)
                next_indeg[node] = -1
                newly_available = []
                for neighbor in self.adj[node]:
                    next_indeg[neighbor] -= 1
                    if next_indeg[neighbor] == 0:
                        newly_available.append(neighbor)

                remaining_available = current_available[:i] + current_available[i+1:]
                next_available = sorted(remaining_available + newly_available)

                dfs(path, next_indeg, next_available)
                path.pop()

        dfs([], indeg, available)
        return result

    def longest_path(self) -> int:
        if self.has_cycle():
            return -1

        topo = self.topological_sort()
        dist = [0] * self.n
        for u in topo:
            for v in self.adj[u]:
                if dist[u] + 1 > dist[v]:
                    dist[v] = dist[u] + 1
        return max(dist) if self.n > 0 else 0

