from typing import Any, Optional

@dataclass
class Event:
    start: float
    end: float
    title: str
    priority: int  # higher = more important

class Calendar:
    def __init__(self):
        self.events: list[Event] = []

    def add_event(self, event: Event) -> list[Event]:
        if event.start >= event.end:
            raise ValueError("start must be less than end")

        affected = []
        to_remove = []
        to_add = []
        has_conflict = False

        for existing in self.events:
            if existing.start < event.end and existing.end > event.start:
                has_conflict = True
                if event.priority > existing.priority:
                    to_remove.append(existing)
                    if existing.start < event.start:
                        to_add.append(Event(existing.start, event.start, existing.title, existing.priority))
                    if existing.end > event.end:
                        to_add.append(Event(event.end, existing.end, existing.title, existing.priority))
                    affected.append(existing)
                else:
                    frag1 = Event(event.start, existing.start, event.title, event.priority)
                    frag2 = Event(existing.end, event.end, event.title, event.priority)
                    if frag1.start < frag1.end:
                        to_add.append(frag1)
                        affected.append(frag1)
                    if frag2.start < frag2.end:
                        to_add.append(frag2)
                        affected.append(frag2)

        if not has_conflict or to_remove:
            to_add.append(event)

        for e in to_remove:
            self.events.remove(e)
        for e in to_add:
            if e.start < e.end:
                self.events.append(e)

        return affected

    def get_events(self, start: float, end: float) -> list[Event]:
        return sorted(
            [e for e in self.events if e.start < end and e.end > start],
            key=lambda e: e.start
        )

    def free_slots(self, start: float, end: float, min_duration: float = 0) -> list[tuple[float, float]]:
        events = sorted(
            [e for e in self.events if e.start < end and e.end > start],
            key=lambda e: e.start
        )
        slots = []
        current = start
        for e in events:
            if e.start > current:
                if e.start - current >= min_duration:
                    slots.append((current, e.start))
            current = max(current, e.end)
        if current < end:
            if end - current >= min_duration:
                slots.append((current, end))
        return slots

    def utilization(self, start: float, end: float) -> float:
        if end <= start:
            return 0.0
        overlaps = sorted(
            [(max(e.start, start), min(e.end, end)) for e in self.events if e.start < end and e.end > start],
            key=lambda x: x[0]
        )
        occupied = 0.0
        if overlaps:
            curr_start, curr_end = overlaps[0]
            for s, e in overlaps[1:]:
                if s < curr_end:
                    curr_end = max(curr_end, e)
                else:
                    occupied += curr_end - curr_start
                    curr_start, curr_end = s, e
            occupied += curr_end - curr_start
        return min(occupied / (end - start), 1.0)

def regex_match(pattern: str, text: str) -> bool:
    pos = 0
    states = []

    class NFAState:
        def __init__(self, idx):
            self.idx = idx
            self.transitions = {}
            self.epsilon = []
    class NFAFragment:
        def __init__(self, start, end):
            self.start = start
            self.end = end
    class Node: pass
    class Literal(Node):
        def __init__(self, ch): self.ch = ch
    class Dot(Node): pass
    class CharClass(Node):
        def __init__(self, chars, negated): self.chars = chars; self.negated = negated
    class Concat(Node):
        def __init__(self, *nodes): self.nodes = nodes
    class Alt(Node):
        def __init__(self, *nodes): self.nodes = nodes
    class Star(Node):
        def __init__(self, node): self.node = node
    class Plus(Node):
        def __init__(self, node): self.node = node
    class Question(Node):
        def __init__(self, node): self.node = node

    def peek():
        return pattern[pos] if pos < len(pattern) else None
    def consume():
        nonlocal pos
        ch = pattern[pos]
        pos += 1
        return ch

    def parse_alt():
        nodes = [parse_concat()]
        while peek() == '|':
            consume()
            nodes.append(parse_concat())
        if len(nodes) == 1:
            return nodes[0]
        return Alt(*nodes)

    def parse_concat():
        nodes = []
        while peek() is not None and peek() not in '|)':
            nodes.append(parse_atom())
        if len(nodes) == 1:
            return nodes[0]
        return Concat(*nodes)

    def parse_atom():
        ch = peek()
        if ch is None:
            return Literal('')
        if ch == '(':
            consume()
            node = parse_alt()
            if peek() == ')':
                consume()
        elif ch == '[':
            node = parse_char_class()
        elif ch == '.':
            consume()
            node = Dot()
        elif ch == '\\':
            consume()
            node = Literal(consume())
        else:
            consume()
            node = Literal(ch)

        if peek() in '*+?':
            q = consume()
            if q == '*':
                return Star(node)
            elif q == '+':
                return Plus(node)
            elif q == '?':
                return Question(node)
        return node

    def parse_char_class():
        consume() # [
        negated = False
        if peek() == '^':
            negated = True
            consume()
        chars = set()
        while peek() is not None and peek() != ']':
            if peek() == '\\' and pos + 1 < len(pattern):
                consume()
                chars.add(consume())
            else:
                start = consume()
                if peek() == '-' and pos + 1 < len(pattern) and pattern[pos] != ']':
                    consume()
                    end = consume()
                    chars.update(chr(c) for c in range(ord(start), ord(end)+1))
                else:
                    chars.add(start)
        if peek() == ']':
            consume()
        return CharClass(chars, negated)

    def build(node):
        if isinstance(node, Literal):
            s = NFAState(len(states))
            e = NFAState(len(states))
            states.extend([s, e])
            if node.ch:
                s.transitions[node.ch] = [e]
            return NFAFragment(s, e)
        elif isinstance(node, Dot):
            s = NFAState(len(states))
            e = NFAState(len(states))
            states.extend([s, e])
            s.epsilon.append(e)
            return NFAFragment(s, e)
        elif isinstance(node, CharClass):
            s = NFAState(len(states))
            e = NFAState(len(states))
            states.extend([s, e])
            if node.negated:
                s.epsilon.append(e)
                for c in node.chars:
                    s.transitions[c] = []
            else:
                for c in node.chars:
                    s.transitions[c] = [e]
            return NFAFragment(s, e)
        elif isinstance(node, Concat):
            frags = [build(n) for n in node.nodes]
            if not frags:
                s = NFAState(len(states))
                e = NFAState(len(states))
                states.extend([s, e])
                return NFAFragment(s, e)
            start = frags[0].start
            end = frags[-1].end
            for i in range(len(frags)-1):
                frags[i].end.epsilon.extend(frags[i+1].start.epsilon)
                frags[i].end.epsilon.append(frags[i+1].start)
            return NFAFragment(start, end)
        elif isinstance(node, Alt):
            s = NFAState(len(states))
            e = NFAState(len(states))
            states.extend([s, e])
            for n in node.nodes:
                frag = build(n)
                s.epsilon.extend(frag.start.epsilon)
                s.epsilon.append(frag.start)
                frag.end.epsilon.extend(e.epsilon)
                frag.end.epsilon.append(e)
            return NFAFragment(s, e)
        elif isinstance(node, Star):
            s = NFAState(len(states))
            e = NFAState(len(states))
            states.extend([s, e])
            frag = build(node.node)
            s.epsilon.extend(frag.start.epsilon)
            s.epsilon.append(frag.start)
            s.epsilon.append(e)
            frag.end.epsilon.extend(e.epsilon)
            frag.end.epsilon.append(e)
            frag.end.epsilon.extend(s.epsilon)
            frag.end.epsilon.append(s)
            return NFAFragment(s, e)
        elif isinstance(node, Plus):
            s = NFAState(len(states))
            e = NFAState(len(states))
            states.extend([s, e])
            frag = build(node.node)
            s.epsilon.extend(frag.start.epsilon)
            s.epsilon.append(frag.start)
            frag.end.epsilon.extend(e.epsilon)
            frag.end.epsilon.append(e)
            frag.end.epsilon.extend(s.epsilon)
            frag.end.epsilon.append(s)
            return NFAFragment(s, e)
        elif isinstance(node, Question):
            s = NFAState(len(states))
            e = NFAState(len(states))
            states.extend([s, e])
            frag = build(node.node)
            s.epsilon.extend(frag.start.epsilon)
            s.epsilon.append(frag.start)
            frag.end.epsilon.extend(e.epsilon)
            frag.end.epsilon.append(e)
            s.epsilon.append(e)
            return NFAFragment(s, e)
        return NFAFragment(None, None)

    def epsilon_closure(states):
        stack = list(states)
        closure = set(states)
        while stack:
            s = stack.pop()
            for t in s.epsilon:
                if t not in closure:
                    closure.add(t)
                    stack.append(t)
        return closure

    def move(states, char):
        next_states = set()
        for s in states:
            if char in s.transitions:
                for t in s.transitions[char]:
                    next_states.add(t)
        return next_states

    root = parse_alt()
    frag = build(root)
    start_states = epsilon_closure([frag.start])
    end_state = frag.end

    current_states = start_states
    for char in text:
        next_states = move(current_states, char)
        current_states = epsilon_closure(next_states)
        if not current_states:
            return False

    return any(s is end_state for s in current_states)

import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, num_virtual_nodes: int = 150):
        self.num_virtual_nodes = num_virtual_nodes
        self.ring_hashes = []
        self.ring_nodes = []
        self.nodes = set()

    def add_node(self, node_id: str) -> None:
        if node_id in self.nodes:
            return
        self.nodes.add(node_id)
        for i in range(self.num_virtual_nodes):
            vnode = f"{node_id}#v{i}"
            h = int(hashlib.md5(vnode.encode()).hexdigest(), 16)
            idx = bisect.bisect_left(self.ring_hashes, h)
            self.ring_hashes.insert(idx, h)
            self.ring_nodes.insert(idx, node_id)

    def remove_node(self, node_id: str) -> None:
        if node_id not in self.nodes:
            raise KeyError(node_id)
        self.nodes.discard(node_id)
        self.ring_hashes = [h for h, n in zip(self.ring_hashes, self.ring_nodes) if n != node_id]
        self.ring_nodes = [n for n in self.ring_nodes if n != node_id]

    def get_node(self, key: str) -> str | None:
        if not self.ring_hashes:
            return None
        h = int(hashlib.md5(key.encode()).hexdigest(), 16)
        idx = bisect.bisect_right(self.ring_hashes, h)
        if idx == len(self.ring_hashes):
            idx = 0
        return self.ring_nodes[idx]

    def get_nodes_for_key(self, key: str, num_replicas: int = 3) -> list[str]:
        if not self.ring_hashes:
            return []
        h = int(hashlib.md5(key.encode()).hexdigest(), 16)
        idx = bisect.bisect_right(self.ring_hashes, h)
        if idx == len(self.ring_hashes):
            idx = 0

        nodes = []
        seen = set()
        n = len(self.ring_hashes)
        i = idx
        while len(nodes) < num_replicas and len(seen) < len(self.nodes):
            node = self.ring_nodes[i]
            if node not in seen:
                nodes.append(node)
                seen.add(node)
            i = (i + 1) % n
        return nodes

